export type ThemeType = 'indigo' | 'obsidian' | 'nordic' | 'cyber' | 'coffee';

export interface Clause {
    id: string;
    code: string;
    title: string;
    description: string;
    subClauses?: Clause[];
}

export interface Group {
    id: string;
    title: string;
    icon: string;
    clauses: Clause[];
}

export interface Standard {
    name: string;
    description: string;
    groups: Group[];
}

export interface StandardsData {
    [key: string]: Standard;
}

export interface AuditInfo {
    company: string;
    smo: string;
    department: string;
    interviewee: string;
    auditor: string;
    type: string;
}

export type FindingStatus = 'COMPLIANT' | 'NC_MAJOR' | 'NC_MINOR' | 'OFI' | 'N_A';
export type FindingsViewMode = 'list' | 'matrix';

export interface AnalysisResult {
    clauseId: string;
    status: FindingStatus;
    reason: string;
    suggestion: string;
    evidence: string;
    conclusion_report: string;
}

export interface ApiKeyProfile {
    id: string;
    label: string;
    key: string;
    status: 'valid' | 'invalid' | 'quota_exceeded' | 'checking' | 'unknown' | 'referrer_error';
    activeModel?: string;
    lastResetDate?: string;
    latency: number;
    lastChecked: string;
}

export interface SessionSnapshot {
    id: string;
    timestamp: number;
    label: string;
    triggerType: 'AUTO_SAVE' | 'MANUAL_BACKUP';
    data: {
        standardKey: string;
        auditInfo: AuditInfo;
        selectedClauses: string[];
        evidence: string;
        analysisResult: AnalysisResult[] | null;
        selectedFindings: Record<string, boolean>;
        finalReportText: string | null;
    };
}

