            {toastMsg && <Toast message={toastMsg} onClose={() => setToastMsg(null)} />}

            {aiError && (
                <div className={`fixed z-[9999] top-20 right-5 w-96 layer-card layer-elevated p-4 border-l-4 border-red-500 animate-spring-up transition-all duration-300 ${isErrorClosing ? 'opacity-0 translate-x-4' : 'opacity-100 translate-x-0'}`}>
                    <div className="flex justify-between items-start">
                        <div className="flex items-center gap-2 text-red-500 font-black uppercase text-xs tracking-tighter">
                            <Icon name="AlertCircle" size={20}/><span>System Alert</span>
                        </div>
                        <button onClick={dismissError} className="text-[var(--text-muted)] hover:text-red-500 transition-colors p-1 rounded-full"><Icon name="X" size={18}/></button>
                    </div>
                    <p className="text-xs text-[var(--text-main)] leading-relaxed mt-2 font-medium">{aiError}</p>
                </div>
            )}

            <Header 
                isSidebarOpen={isSidebarOpen}
                setIsSidebarOpen={setIsSidebarOpen}
                displayBadge={displayBadge}
                badgeColorClass="bg-[var(--accent)] text-white"
                setIsCmdPaletteOpen={setIsCmdPaletteOpen}
                fontSizeScale={fontSizeScale}
                setFontSizeScale={setFontSizeScale}
                isDarkMode={isDarkMode}
                setIsDarkMode={setIsDarkMode}
                isSystemHealthy={isSystemHealthy}
                onOpenSettings={() => setShowSettingsModal(true)}
                onOpenAbout={() => setShowAboutModal(true)}
                activeTheme={activeTheme}
                onSetTheme={handleSetTheme}
            />

            <main className="flex-1 flex overflow-hidden relative">
                <div className={`${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 transition-transform duration-300 ease-soft z-[60] h-full`}>
                    <Sidebar 
                        key={sessionKey} 
                        isOpen={isSidebarOpen} 
                        width={sidebarWidth} 
                        setWidth={setSidebarWidth} 
                        standards={allStandards} 
                        standardKey={standardKey} 
                        setStandardKey={handleSetStandardKey} 
                        auditInfo={auditInfo} 
                        setAuditInfo={setAuditInfo} 
                        selectedClauses={selectedClauses} 
                        setSelectedClauses={setSelectedClauses} 
                        onAddNewStandard={() => setShowAddStandardModal(true)} 
                        onUpdateStandard={handleUpdateStandard} 
                        onResetStandard={handleResetStandard} 
                        onReferenceClause={handleOpenReferenceClause} 
                        showIntegrityModal={showIntegrityModal} 
                        setShowIntegrityModal={setShowIntegrityModal}
                        knowledgeFileName={knowledgeFileName}
                        knowledgeBase={knowledgeBase}
                        onKnowledgeUpload={handleKnowledgeUpload}
                        onClearKnowledge={handleClearKnowledge}
                    />
                </div>

                <div className="flex-1 flex flex-col min-w-0 relative p-4 md:p-6 gap-6">
                    <div className="layer-card p-2 flex justify-between items-center bg-[var(--bg-card)]/80 backdrop-blur shadow-lg">
                        <div className="flex-1 max-w-2xl">
                            <div ref={tabsContainerRef} className="relative flex bg-[var(--bg-surface)] p-1 rounded-2xl layer-inner overflow-hidden">
                                <div className="absolute top-1 bottom-1 rounded-xl transition-all duration-500 ease-soft z-0" style={{ left: tabStyle.left, width: tabStyle.width, opacity: tabStyle.opacity, backgroundColor: tabStyle.color }} />
                                {tabsList.map((tab, idx) => (
                                    <button key={tab.id} ref={el => { tabsRef.current[idx] = el; }} onClick={() => setLayoutMode(tab.id as LayoutMode)} className={`flex-1 relative z-10 flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl text-xs font-black transition-all duration-300 ${layoutMode === tab.id ? 'text-white' : 'text-[var(--text-muted)] hover:text-[var(--text-main)]'}`}>
                                        <Icon name={tab.icon} size={16}/> 
                                        <span className="hidden sm:inline uppercase tracking-widest">{tab.label}</span>
                                    </button>
                                ))}
                            </div>
                        </div>
                        <div className="flex gap-2 items-center pl-4 border-l border-[var(--border-main)]">
                            <button onClick={() => setShowRecallModal(true)} className="h-10 px-4 layer-card flex items-center gap-2 text-xs font-bold text-[var(--text-main)]">
                                <Icon name="History" size={18}/>
                                <span className="hidden lg:inline">Recall</span>
                            </button>
                            <button onClick={handleNewSession} className="h-10 px-4 layer-card bg-[var(--accent)] text-white border-none flex items-center gap-2 text-xs font-black uppercase tracking-tighter">
                                <Icon name="Session4_FilePlus" size={18}/>
                                <span className="hidden lg:inline">New Session</span>
                            </button>
                        </div>
                    </div>

                    <div className="flex-1 layer-card overflow-hidden p-6 relative animate-spring-up bg-[var(--bg-card)]">
                        {layoutMode === 'evidence' && (
                            <EvidenceView
                                evidence={evidence} setEvidence={setEvidence} uploadedFiles={uploadedFiles}
                                setUploadedFiles={setUploadedFiles} onOcrProcess={handleOcrUpload}
                                isOcrLoading={isOcrLoading} onAnalyze={handleAnalyze}
                                isReadyForAnalysis={isReadyForAnalysis} isAnalyzeLoading={isAnalyzeLoading}
                                analyzeTooltip="Analyze" onExport={startSmartExport}
                                evidenceLanguage={evidenceLanguage} setEvidenceLanguage={setEvidenceLanguage}
                                textareaRef={evidenceTextareaRef}
                            />
                        )}
                        {layoutMode === 'findings' && (
                            <FindingsView
                                analysisResult={analysisResult} setAnalysisResult={setAnalysisResult}
                                selectedFindings={selectedFindings} setSelectedFindings={setSelectedFindings}
                                isAnalyzeLoading={isAnalyzeLoading} loadingMessage={loadingMessage}
                                currentAnalyzingClause={currentAnalyzingClause} viewMode={findingsViewMode}
                                setViewMode={setFindingsViewMode} focusedFindingIndex={focusedFindingIndex}
                                setFocusedFindingIndex={setFocusedFindingIndex} onExport={startSmartExport}
                                notesLanguage={notesLanguage} setNotesLanguage={setNotesLanguage}
                            />
                        )}
                        {layoutMode === 'report' && (
                            <ReportView
                                finalReportText={finalReportText} setFinalReportText={setFinalReportText}
                                isReportLoading={isReportLoading} loadingMessage={loadingMessage}
                                templateFileName={templateFileName} handleTemplateUpload={() => {}}
                                handleGenerateReport={handleGenerateReport} isReadyToSynthesize={isReadyToSynthesize}
                                onExport={startSmartExport} exportLanguage={exportLanguage} setExportLanguage={setExportLanguage}
                            />
                        )}
                    </div>
                </div>
            </main>

            {/* MODALS GIỮ NGUYÊN STYLE NHƯNG BAO BỌC BỞI THEME LỚP NỔI */}
            <CommandPaletteModal isOpen={isCmdPaletteOpen} onClose={() => setIsCmdPaletteOpen(false)} actions={[]} onSelectAction={() => {}} />
            <ReleaseNotesModal isOpen={showAboutModal} onClose={() => setShowAboutModal(false)} />
            <SettingsModal isOpen={showSettingsModal} onClose={() => setShowSettingsModal(false)} apiKeys={apiKeys} newKeyInput={newKeyInput} setNewKeyInput={setNewKeyInput} isCheckingKey={isCheckingKey} handleAddKey={handleAddKey} activeKeyId={activeKeyId} editingKeyId={editingKeyId} editLabelInput={editLabelInput} setEditLabelInput={setEditLabelInput} handleSaveLabel={handleSaveLabel} handleStartEdit={handleStartEdit} handleRefreshStatus={handleRefreshStatus} handleDeleteKey={handleDeleteKey} isAutoCheckEnabled={isAutoCheckEnabled} toggleAutoCheck={toggleAutoCheck} />
            <AddStandardModal isOpen={showAddStandardModal} onClose={() => setShowAddStandardModal(false)} onAdd={handleAddStandard} />
            <RecallModal isOpen={showRecallModal} onClose={() => setShowRecallModal(false)} onRestore={handleRestoreSnapshot} />
            <ReferenceClauseModal isOpen={referenceClauseState.isOpen} onClose={() => setReferenceClauseState(p => ({...p, isOpen: false}))} clause={referenceClauseState.clause} standardName={allStandards[standardKey]?.name || ""} fullText={referenceClauseState.fullText} isLoading={referenceClauseState.isLoading} onInsert={handleInsertReferenceText} />
        </div>
    );
}

import React, { useState } from 'react';
import { Icon, FontSizeController } from './UI';
import { ThemeType } from '../types';

interface HeaderProps {
    isSidebarOpen: boolean;
    setIsSidebarOpen: (v: boolean) => void;
    displayBadge: string;
    badgeColorClass: string;
    setIsCmdPaletteOpen: (v: boolean) => void;
    fontSizeScale: number;
    setFontSizeScale: React.Dispatch<React.SetStateAction<number>>;
    isDarkMode: boolean;
    setIsDarkMode: (v: boolean) => void;
    isSystemHealthy: boolean;
    onOpenSettings: () => void;
    onOpenAbout: () => void;
    activeTheme: ThemeType;
    onSetTheme: (theme: ThemeType) => void;
}

export const Header: React.FC<HeaderProps> = ({
    isSidebarOpen, setIsSidebarOpen, displayBadge, badgeColorClass,
    setIsCmdPaletteOpen, fontSizeScale, setFontSizeScale,
    isDarkMode, setIsDarkMode, isSystemHealthy,
    onOpenSettings, onOpenAbout, activeTheme, onSetTheme
}) => {
    const [showThemePicker, setShowThemePicker] = useState(false);

    const themes: { id: ThemeType, label: string, color: string }[] = [
        { id: 'indigo', label: 'Indigo Night', color: 'bg-indigo-600' },
        { id: 'obsidian', label: 'Obsidian Gold', color: 'bg-yellow-500' },
        { id: 'nordic', label: 'Nordic Frost', color: 'bg-sky-400' },
        { id: 'cyber', label: 'Cyber Neon', color: 'bg-cyan-400' },
        { id: 'coffee', label: 'Coffee Paper', color: 'bg-amber-800' },
    ];

    return (
        <header className="flex-shrink-0 px-6 h-20 border-b border-[var(--border-main)] bg-[var(--bg-sidebar)] z-[70] relative flex justify-between items-center theme-transition shadow-sm">
            <div className="flex items-center gap-6">
                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-3 layer-card hover:bg-[var(--bg-surface)] text-[var(--accent)] transition-all active:scale-90">
                    <Icon name={isSidebarOpen ? "CollapsePanel" : "ExpandPanel"} size={20} />
                </button>
                <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-[var(--accent)] rounded-2xl flex items-center justify-center text-white shadow-lg shadow-[var(--accent)]/20">
                        <Icon name="TDLogo" size={24} />
                    </div>
                    <h1 className="text-xl font-black tracking-tighter text-[var(--text-main)] uppercase">ISO Audit <span className="font-light opacity-50">Pro</span></h1>
                    <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest shadow-sm ${badgeColorClass}`}>{displayBadge}</span>
                </div>
            </div>

            <div className="flex items-center gap-3">
                {/* Theme Picker */}
                <div className="relative">
                    <button 
                        onClick={() => setShowThemePicker(!showThemePicker)}
                        className="p-3 layer-card text-[var(--text-muted)] hover:text-[var(--accent)]"
                        title="Change Theme"
                    >
                        <Icon name="Snowflake" size={20} />
                    </button>
                    {showThemePicker && (
                        <>
                            <div className="fixed inset-0 z-10" onClick={() => setShowThemePicker(false)}></div>
                            <div className="absolute right-0 mt-3 w-48 layer-card layer-elevated p-2 z-20 space-y-1 animate-spring-up">
                                <p className="text-[10px] font-black text-[var(--text-muted)] uppercase p-2 tracking-widest border-b border-[var(--border-main)] mb-1">Visual Themes</p>
                                {themes.map(t => (
                                    <button 
                                        key={t.id}
                                        onClick={() => { onSetTheme(t.id); setShowThemePicker(false); }}
                                        className={`w-full flex items-center justify-between p-2 rounded-xl text-xs font-bold transition-all ${activeTheme === t.id ? 'bg-[var(--accent)] text-white' : 'hover:bg-[var(--bg-surface)] text-[var(--text-main)]'}`}
                                    >
                                        <span>{t.label}</span>
                                        <div className={`w-3 h-3 rounded-full ${t.color} border border-white/20`}></div>
                                    </button>
                                ))}
                            </div>
                        </>
                    )}
                </div>

                <div className="h-8 w-px bg-[var(--border-main)] mx-2"></div>

                <button onClick={() => setIsCmdPaletteOpen(true)} className="p-3 layer-card text-[var(--text-muted)] hover:text-[var(--accent)]" title="Commands">
                    <Icon name="Session6_Zap" size={20}/>
                </button>

                <FontSizeController 
                    fontSizeScale={fontSizeScale} 
                    adjustFontSize={(dir: 'increase' | 'decrease') => setFontSizeScale(prev => dir === 'increase' ? Math.min(prev + 0.1, 1.5) : Math.max(prev - 0.1, 0.7))} 
                />

                <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-3 layer-card text-[var(--text-muted)]" title="Toggle Mode">
                    <Icon name={isDarkMode ? "Sun" : "Moon"} size={20}/>
                </button>

                <button onClick={onOpenSettings} className="group relative w-12 h-12 flex items-center justify-center layer-card border-none overflow-hidden" title="Settings">
                    <div className={`absolute inset-0 opacity-10 animate-pulse ${isSystemHealthy ? 'bg-emerald-500' : 'bg-red-500'}`}></div>
                    <div className={`w-3 h-3 rounded-full shadow-lg ring-4 ring-white/10 ${isSystemHealthy ? 'bg-emerald-500' : 'bg-red-500'}`}></div>
                </button>

                <button onClick={onOpenAbout} className="p-3 layer-card text-[var(--text-muted)] hover:text-[var(--accent)]" title="Info">
                    <Icon name="Info" size={20}/>
                </button>
            </div>
        </header>
    );
};
